super easy fix, this adds both geminii-3.5-flash and gemma-4 (you have to create an endpoint also)
```
  // Provider configuration
  "provider": {
    "google-vertex": {
      "options": {
        "project": "<project-id>",
        "location": "global"
      },
      "models": {
        "gemini-3.5-flash": {
          "name": "Gemini 3.5 Flash"
        }
      }
    },
    // Gemma4 requires separate config and auth setup
    "vertex-maas": {
      "npm": "@ai-sdk/openai-compatible",
      "name": "Vertex AI MaaS",
      "options": {
        "baseURL": "https://aiplatform.googleapis.com/v1beta1/projects/<project-id>/locations/global/endpoints/openapi",
        // export GOOGLE_VERTEX_BEARER_TOKEN=$(gcloud auth print-access-token)
        "apiKey": "{env:GOOGLE_VERTEX_BEARER_TOKEN}"
      },
      "models": {
        "google/gemma-4-26b-a4b-it-maas": {
          "name": "Gemma 4 26B (MaaS API)",
          "tool_call": false
        }
      }
    }
  },
```
